import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../utils/api';

export default function Register() {
  const [form, setForm] = useState({ account_type:'student', member_id:'', name:'', email:'', password:'', confirm_password:'', department:'', batch:'', mobile:'', address:'', gender:'' });
  const [error, setError]     = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass]   = useState(false);
  const [showPass2, setShowPass2] = useState(false);
  const [scale, setScale] = useState(1);
  const navigate = useNavigate();
  const set = (k:string, v:string) => setForm(f=>({...f,[k]:v}));

  useEffect(() => {
    let dir = 1;
    const id = setInterval(() => {
      setScale(s => { const n=s+dir*0.0007; if(n>=1.1)dir=-1; if(n<=1.0)dir=1; return parseFloat(n.toFixed(4)); });
    }, 30);
    return () => clearInterval(id);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault(); setError(''); setSuccess('');
    if (form.password !== form.confirm_password) { setError('Passwords do not match!'); return; }
    if (form.password.length < 6) { setError('Password must be at least 6 characters!'); return; }
    setLoading(true);
    try {
      await api.post('/auth/register', form);
      setSuccess('Registration successful! Waiting for librarian approval.');
      setTimeout(() => navigate('/login'), 3000);
    } catch (e:any) { setError(e.response?.data?.message || 'Registration failed'); }
    finally { setLoading(false); }
  };

  const inp: React.CSSProperties = { width:'100%', padding:'14px 16px', background:'rgba(255,255,255,0.07)', border:'1.5px solid rgba(255,255,255,0.12)', borderRadius:12, fontSize:15, color:'#fff', fontFamily:'inherit', outline:'none', boxSizing:'border-box', transition:'all .2s' };
  const lbl: React.CSSProperties = { display:'block', fontSize:12, fontWeight:700, color:'rgba(255,255,255,0.5)', marginBottom:8, letterSpacing:'1px', textTransform:'uppercase' };

  return (
    <div style={{ minHeight:'100vh', width:'100%', position:'relative', display:'flex', alignItems:'center', justifyContent:'center', fontFamily:"'DM Sans',sans-serif", overflow:'hidden', padding:'28px 20px' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700&family=DM+Sans:wght@400;500;600;700&display=swap');
        * { box-sizing:border-box; }
        .ri:focus { border-color:#c9a84c !important; box-shadow:0 0 0 3px rgba(201,168,76,0.2) !important; outline:none; }
        .ri::placeholder { color:rgba(255,255,255,0.22) !important; }
        .rbtn:hover:not(:disabled) { background:#d4b55a !important; transform:translateY(-2px); box-shadow:0 12px 32px rgba(201,168,76,0.45) !important; }
        .rbtn:disabled { opacity:.65; cursor:not-allowed; }
        .card-up { animation:cUp .55s cubic-bezier(.16,1,.3,1) forwards; }
        @keyframes cUp { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:translateY(0)} }
        .ttype:hover { border-color:rgba(201,168,76,0.5) !important; }
        .eye2:hover { color:rgba(255,255,255,0.85) !important; }
      `}</style>

      {/* BG */}
      <div style={{ position:'absolute', inset:0, zIndex:0, backgroundImage:'url(/library-bg.jpg)', backgroundSize:'cover', backgroundPosition:'center', transform:`scale(${scale})`, filter:'brightness(0.4)', transition:'transform .1s linear', willChange:'transform' }} />
      <div style={{ position:'absolute', inset:0, zIndex:1, background:'radial-gradient(ellipse at center, transparent 20%, rgba(0,0,0,0.7) 100%)' }} />

      <div className="card-up" style={{ position:'relative', zIndex:2, width:'100%', maxWidth:540, display:'flex', flexDirection:'column', alignItems:'center' }}>

        {/* Header */}
        <p style={{ fontSize:13, fontWeight:600, letterSpacing:'1.5px', color:'rgba(255,255,255,0.48)', textTransform:'uppercase', marginBottom:10, textAlign:'center' }}>
          Bangladesh Army University of Science and Technology
        </p>
        <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:48, fontWeight:700, color:'#fff', margin:'0 0 8px', textAlign:'center', letterSpacing:'-1px', lineHeight:1 }}>
          LibraryMS
        </h1>
        <div style={{ width:50, height:2, background:'linear-gradient(90deg,transparent,#c9a84c,transparent)', margin:'0 auto 26px' }} />

        {/* Glass Card */}
        <div style={{ width:'100%', background:'rgba(12,12,22,0.7)', backdropFilter:'blur(28px)', WebkitBackdropFilter:'blur(28px)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:24, padding:'36px 34px 28px', boxShadow:'0 32px 80px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.07)' }}>

          <h2 style={{ fontSize:26, fontWeight:700, color:'#fff', margin:'0 0 6px', textAlign:'center' }}>Create Account</h2>
          <p style={{ fontSize:15, color:'rgba(255,255,255,0.35)', margin:'0 0 24px', textAlign:'center' }}>Register to access the library</p>

          {error   && <div style={{ background:'rgba(220,38,38,0.15)', border:'1px solid rgba(220,38,38,0.35)', color:'#fca5a5', padding:'12px 16px', borderRadius:11, fontSize:14, marginBottom:18, display:'flex', alignItems:'center', gap:10 }}><span>⚠</span>{error}</div>}
          {success && <div style={{ background:'rgba(5,150,105,0.15)', border:'1px solid rgba(5,150,105,0.35)', color:'#6ee7b7', padding:'12px 16px', borderRadius:11, fontSize:14, marginBottom:18, display:'flex', alignItems:'center', gap:10 }}><span>✓</span>{success}</div>}

          <form onSubmit={handleSubmit}>
            {/* Account Type */}
            <div style={{ marginBottom:18 }}>
              <label style={lbl}>Account Type *</label>
              <div style={{ display:'flex', gap:10 }}>
                {['student','staff'].map(t=>(
                  <button key={t} type="button" className="ttype" onClick={()=>set('account_type',t)}
                    style={{ flex:1, padding:'13px', border:`1.5px solid ${form.account_type===t?'#c9a84c':'rgba(255,255,255,0.12)'}`, borderRadius:12, background:form.account_type===t?'rgba(201,168,76,0.15)':'rgba(255,255,255,0.05)', color:form.account_type===t?'#c9a84c':'rgba(255,255,255,0.45)', fontSize:15, fontWeight:700, cursor:'pointer', fontFamily:'inherit', transition:'all .2s' }}>
                    {t==='student'?'🎓 Student':'👨‍💼 Staff'}
                  </button>
                ))}
              </div>
            </div>

            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14 }}>
              <div>
                <label style={lbl}>{form.account_type==='student'?'Student ID':'Staff ID'} *</label>
                <input className="ri" style={inp} value={form.member_id} onChange={e=>set('member_id',e.target.value)} placeholder={form.account_type==='student'?'e.g. 20210101':'e.g. STF001'} required />
              </div>
              <div>
                <label style={lbl}>Full Name *</label>
                <input className="ri" style={inp} value={form.name} onChange={e=>set('name',e.target.value)} placeholder="Your full name" required />
              </div>
              <div>
                <label style={lbl}>Department *</label>
                <input className="ri" style={inp} value={form.department} onChange={e=>set('department',e.target.value)} placeholder="e.g. CSE" required />
              </div>
              {form.account_type==='student'?(
                <div>
                  <label style={lbl}>Batch *</label>
                  <input className="ri" style={inp} value={form.batch} onChange={e=>set('batch',e.target.value)} placeholder="e.g. 2021" required />
                </div>
              ):<div />}
              <div>
                <label style={lbl}>Mobile *</label>
                <input className="ri" style={inp} value={form.mobile} onChange={e=>set('mobile',e.target.value)} placeholder="01XXXXXXXXX" required />
              </div>
              <div>
                <label style={lbl}>Gender *</label>
                <select className="ri" style={{ ...inp, appearance:'none' as any }} value={form.gender} onChange={e=>set('gender',e.target.value)} required>
                  <option value="" style={{ background:'#1a1a2e' }}>Select gender</option>
                  <option value="male" style={{ background:'#1a1a2e' }}>Male</option>
                  <option value="female" style={{ background:'#1a1a2e' }}>Female</option>
                  <option value="other" style={{ background:'#1a1a2e' }}>Other</option>
                </select>
              </div>
              <div style={{ gridColumn:'1/-1' }}>
                <label style={lbl}>Email Address *</label>
                <input className="ri" style={inp} type="email" value={form.email} onChange={e=>set('email',e.target.value.toLowerCase())} placeholder="your@email.com" required />
              </div>
              <div style={{ position:'relative' }}>
                <label style={lbl}>Password *</label>
                <input className="ri" style={{ ...inp, paddingRight:48 }} type={showPass?'text':'password'} value={form.password} onChange={e=>set('password',e.target.value)} placeholder="Min 6 characters" required />
                <button type="button" className="eye2" onClick={()=>setShowPass(v=>!v)} style={{ position:'absolute', right:14, bottom:12, background:'none', border:'none', color:'rgba(255,255,255,0.32)', cursor:'pointer', fontSize:18, padding:0, transition:'color .2s' }}>{showPass?'🙈':'👁'}</button>
              </div>
              <div style={{ position:'relative' }}>
                <label style={lbl}>Confirm Password *</label>
                <input className="ri" style={{ ...inp, paddingRight:48 }} type={showPass2?'text':'password'} value={form.confirm_password} onChange={e=>set('confirm_password',e.target.value)} placeholder="Repeat password" required />
                <button type="button" className="eye2" onClick={()=>setShowPass2(v=>!v)} style={{ position:'absolute', right:14, bottom:12, background:'none', border:'none', color:'rgba(255,255,255,0.32)', cursor:'pointer', fontSize:18, padding:0, transition:'color .2s' }}>{showPass2?'🙈':'👁'}</button>
              </div>
              <div style={{ gridColumn:'1/-1' }}>
                <label style={lbl}>Address</label>
                <textarea className="ri" style={{ ...inp, minHeight:78, resize:'vertical' }} value={form.address} onChange={e=>set('address',e.target.value)} placeholder="Your full address (optional)" />
              </div>
            </div>

            <button type="submit" disabled={loading} className="rbtn"
              style={{ width:'100%', padding:'16px', background:'#c9a84c', color:'#1a1a2e', border:'none', borderRadius:13, fontSize:16, fontWeight:700, cursor:'pointer', fontFamily:'inherit', marginTop:20, transition:'all .25s', boxShadow:'0 4px 20px rgba(201,168,76,0.3)' }}>
              {loading ? 'Creating account...' : 'Create Account →'}
            </button>
          </form>

          <p style={{ textAlign:'center', fontSize:15, color:'rgba(255,255,255,0.32)', marginTop:18 }}>
            Already have an account?{' '}
            <Link to="/login" style={{ color:'#c9a84c', fontWeight:700, textDecoration:'none' }}>Sign in</Link>
          </p>

          <div style={{ marginTop:16, background:'rgba(201,168,76,0.08)', border:'1px solid rgba(201,168,76,0.18)', borderRadius:11, padding:'12px 16px', display:'flex', alignItems:'flex-start', gap:10 }}>
            <span style={{ fontSize:15, flexShrink:0 }}>⚠️</span>
            <p style={{ fontSize:13, color:'rgba(255,255,255,0.4)', margin:0, lineHeight:1.6 }}>
              After registration, your account needs <strong style={{ color:'#c9a84c' }}>librarian approval</strong> before you can login.
            </p>
          </div>
        </div>

        <p style={{ fontSize:11, color:'rgba(255,255,255,0.18)', marginTop:18, letterSpacing:'1.5px', textTransform:'uppercase', textAlign:'center' }}>
          BAUST · Library Management System
        </p>
      </div>
    </div>
  );
}
